var e=JSON.parse(`[{"id":"idx_0","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","JPN":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 対象者観察","ENG":"CCN No. CSM002M000755-09\\n<color=#ffd34c>Class 3 Subject</color> Clearance Documents\\nAppendix: Subject Surveillance","TWN":"(TWN)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네가 등록한 자료를 검토해 봤네.\\n아직까지 프리드웬 측의 견제는 없나 보군.","JPN":"君が登録した資料を検討してみたな。\\nまだプリドウェン側の牽制はないようであるね。","ENG":"I've reviewed the documents you registered.\\nThere appears to be no coercion from the Friedwen side as of yet.","TWN":"(TWN)자네가 등록한 자료를 검토해 봤네.\\n아직까지 프리드웬 측의 견제는 없나 보군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_2","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현지 요원들이 우수해서 그렇다고 생각해 주시죠.","JPN":"現地要員が優秀でそれでも思ってくれます。","ENG":"I believe that's because the local operatives are excellent.","TWN":"(TWN)현지 요원들이 우수해서 그렇다고 생각해 주시죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_3","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 말이 사실이면 얼마나 좋겠나.","JPN":"その言葉が事実ならどのくらい良いか。","ENG":"How wonderful it would be if that were true.","TWN":"(TWN)그 말이 사실이면 얼마나 좋겠나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_4","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 관찰대상에 대해 추가로 보고드릴 사안이 생겼습니다.","JPN":"そして観察対象について追加でご報告申し上げる事案が生じました。","ENG":"Additionally, a matter has arisen requiring further reporting on the surveillance target.","TWN":"(TWN)그리고 관찰대상에 대해 추가로 보고드릴 사안이 생겼습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_5","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"시급한 안건인가?","JPN":"至急な案件であるか?","ENG":"Is it a time-sensitive matter?","TWN":"(TWN)시급한 안건인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_6","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"잠시 시간 내서 들을 정도는 됩니다.","JPN":"少しの間時間来書を程度はなります。","ENG":"It can be covered within a moment's time.","TWN":"(TWN)잠시 시간 내서 들을 정도는 됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_7","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네가 그렇게 말하니 괜히 무서워지는군.\\n프리드웬에서 새로운 플래그먼트라도 확보한 건가? ","JPN":"君がそのように言うから訳もなく恐ろしくなるね。\\nプリドウェンで新しいプレグモントラも確保するのか?","ENG":"When you put it that way, it makes me anxious for no reason.\\nDid they discover a new fragment in Friedwen?","TWN":"(TWN)자네가 그렇게 말하니 괜히 무서워지는군.\\n프리드웬에서 새로운 플래그먼트라도 확보한 건가? "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_8","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"다행스럽게도 아닙니다.\\n일전에 말씀드린 관찰대상의 전속 동기 때문입니다.","JPN":"幸いにもないです。\\n先日に申し上げた観察対象の専属同期のためです。","ENG":"Fortunately, that is not the case.\\nIt concerns the surveillance target's former affiliation that I mentioned previously.","TWN":"(TWN)다행스럽게도 아닙니다.\\n일전에 말씀드린 관찰대상의 전속 동기 때문입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_9","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 진위 여부 확인 때문에 보류됐던 그 건이군.","JPN":"あ、真偽可否確認のために保留されたその件だね。","ENG":"Ah, the matter that was classified to check the severity?","TWN":"(TWN)아, 진위 여부 확인 때문에 보류됐던 그 건이군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_10","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 특히 워치 습득 과정과 밀접한 관련이 있습니다.","JPN":"はい。特にウォッチ習得過程と密接な関連があります。","ENG":"Yes. There is a particularly close connection to the process of Watch acquisition.","TWN":"(TWN)네. 특히 워치 습득 과정과 밀접한 관련이 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_11","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기존 자료에는 군사 임무 수행 중 획득이라고만 적혀 있더군.","JPN":"既存資料には軍事ミッション遂行中獲得であると書かれていていたよ。","ENG":"In the existing documents, it was only written that he acquired it during military service.","TWN":"(TWN)기존 자료에는 군사 임무 수행 중 획득이라고만 적혀 있더군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_12","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"서류는 가끔씩 사람 눈을 어둡게 만들죠.","JPN":"書類は時たま人目を暗くします。","ENG":"Documents often obscure human eyes.","TWN":"(TWN)서류는 가끔씩 사람 눈을 어둡게 만들죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_13","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하긴, 이 시기면 한창 대환류로 고생할 때지. 마른 하늘에서 뚝 떨어지진 않았겠어.","JPN":"することは、この時期面たけなわ大患類で苦労する時だ。乾いた空から全く離れない。","ENG":"Still, at that time, it was during the Great Reflux chaos. It wouldn't have fallen from a clear sky.","TWN":"(TWN)하긴, 이 시기면 한창 대환류로 고생할 때지. 마른 하늘에서 뚝 떨어지진 않았겠어."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_14","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"힘든 일이 많은 시절이었으니까요.","JPN":"大変な事が多い時代だったからです。","ENG":"It was a time when many difficult things happened.","TWN":"(TWN)힘든 일이 많은 시절이었으니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_15","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"정확한 습득 시점은 대환류가 종식되기 3개월 전이었습니다.","JPN":"正確な習得時点は大患類が終息される3ヶ月前でした。","ENG":"The exact acquisition time was three months before the Great Reflux ended.","TWN":"(TWN)정확한 습득 시점은 대환류가 종식되기 3개월 전이었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_16","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당시 군 복무 중이었던 관찰대상은 템즈 강을 통해 런던으로 진입하는 침식체를 저지하란 지시를 받았습니다.","JPN":"当時軍服務中だった観察対象はテムズ川を通じてロンドンで進入する侵食体を阻止するという指示を受けました。","ENG":"At the time, the surveillance target, who was serving in the military, received orders to suppress an erosion entity infiltrating London via the Thames.","TWN":"(TWN)당시 군 복무 중이었던 관찰대상은 템즈 강을 통해 런던으로 진입하는 침식체를 저지하란 지시를 받았습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_17","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"SIS 소속이라고 하지 않았나? 특수부대에게 상륙 차단 명령을 내렸다고?","JPN":"SIS所属と言わなかったか?特殊部隊に上陸遮断命令を下したと?","ENG":"Didn't you say he was SIS? That they ordered the special forces to board?","TWN":"(TWN)SIS 소속이라고 하지 않았나? 특수부대에게 상륙 차단 명령을 내렸다고?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_18","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"정규군도 바보가 아닙니다.\\n그만큼 상황이 급박했기 때문이죠.","JPN":"正規軍も馬鹿ではないです。\\nそれほど状況が切迫だったからです。","ENG":"The regular army is no fool either.\\nThe situation was that urgent.","TWN":"(TWN)정규군도 바보가 아닙니다.\\n그만큼 상황이 급박했기 때문이죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_19","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당시 런던은 교외에 다수 발생한 활성 침식지대 탓에 외부로부터 고립된 상태였습니다. ","JPN":"当時ロンドンは郊外に多数発生した活性侵食地帯のせいで外部から孤立した状態でした。","ENG":"At the time, London was isolated from the outside due to multiple active erosion zones occurring simultaneously.","TWN":"(TWN)당시 런던은 교외에 다수 발생한 활성 침식지대 탓에 외부로부터 고립된 상태였습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_20","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"수도를 지키는 전력은 활성 침식지대에서 쏟아져 나온 침식체들과 교전 중이었죠.","JPN":"首都を守る電力は活性寝食地帯で溢れ出た侵食体と交戦中でした。","ENG":"The capital's defending forces were engaged in combat with erosion entities pouring out from the active erosion zones.","TWN":"(TWN)수도를 지키는 전력은 활성 침식지대에서 쏟아져 나온 침식체들과 교전 중이었죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_21","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당일 오전 4시 30분 경, 일곱 차례에 걸친 교전이 발발했다고 합니다.","JPN":"当日午前4時30分頃、七回にわたった交戦が勃発したと言います。","ENG":"It is reported that seven engagements occurred around 4:30 AM that day.","TWN":"(TWN)당일 오전 4시 30분 경, 일곱 차례에 걸친 교전이 발발했다고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_22","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"화력을 외각 전선에 집중해야 했던 탓에, 강을 거슬러 올라오는 침식체들은 지휘부의 우선 순위에서 밀려난 것으로 추정됩니다.","JPN":"火力を外角電線に集中しなければならなかったせいに、川をさかのぼってくる侵食体は指揮部のまず順位から追いやられたことで推定されます。","ENG":"As firepower had to be concentrated on the external front line, it is estimated that the erosion entities climbing up the river were pushed aside in the command's priority sequence.","TWN":"(TWN)화력을 외각 전선에 집중해야 했던 탓에, 강을 거슬러 올라오는 침식체들은 지휘부의 우선 순위에서 밀려난 것으로 추정됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_23","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 대신 프리드웬 기관 측에서 대기 중이었던 병력에 비공식적인 지원 요청을 보냈습니다. ","JPN":"その代わりプリドウェン機関側で待機中だった兵力に非公式的な支援要請を送りました。","ENG":"Instead, an informal request for support was sent to the Friedwen agency forces who were on standby.","TWN":"(TWN)그 대신 프리드웬 기관 측에서 대기 중이었던 병력에 비공식적인 지원 요청을 보냈습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_24","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"인터뷰에선 관찰대상과 프리드웬 측 요원이 무척 친밀하게 대화를 나눴다고 합니다. 한 명은 남매였다고 단언했죠.","JPN":"インタビューでは観察対象とプリドウェン側要員がすごく親密に対話を交わしたと言います。一人は兄と妹だったと言い切ったんです。","ENG":"In the interview, it is said that the surveillance target and the Friedwen operative conversed quite amicably. One witness asserted they were siblings.","TWN":"(TWN)인터뷰에선 관찰대상과 프리드웬 측 요원이 무척 친밀하게 대화를 나눴다고 합니다. 한 명은 남매였다고 단언했죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_25","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"상륙을 저지하기 위해 투입된 병력 중 87%는 현장에서 전사하게 됩니다.","JPN":"上陸を阻止するために投入された兵力中87%は現場で戦死するようになります。","ENG":"Of the troops deployed to maintain the landing, 87% were killed in action at the scene.","TWN":"(TWN)상륙을 저지하기 위해 투입된 병력 중 87%는 현장에서 전사하게 됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_26","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신원이 밝혀지지 않은 프리드웬 측 요원도 그중 한 명이었죠.","JPN":"身元が明かされないプリドウェン側要員もなかでも一人でした。","ENG":"The unidentified Friedwen operative was one of them.","TWN":"(TWN)신원이 밝혀지지 않은 프리드웬 측 요원도 그중 한 명이었죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_27","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"전사한 카운터의 워치를 계승했단 얘기군.","JPN":"戦死したカウンターのウォッチを継承したという話だね。","ENG":"So you're saying he inherited the Watch from the fallen Counter.","TWN":"(TWN)전사한 카운터의 워치를 계승했단 얘기군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_28","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"채집한 인터뷰 내용들은 공통적으로 그러한 가능성을 시사하고 있습니다.","JPN":"採集したインタビュー内容は共通的にこのような可能性を示唆しています。","ENG":"The collected interview contents generally suggest such a possibility.","TWN":"(TWN)채집한 인터뷰 내용들은 공통적으로 그러한 가능성을 시사하고 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_29","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 합법적인 수단으로 둘 사이에 어떤 얘기가 오갔을지 파악하기는 어려워 보입니다.","JPN":"しかし合法的な手段で二つの間にどのような話が行き交ったのか把握することは難しく見えます。","ENG":"However, it is difficult to determine what kind of conversation took place between the two through legitimate means.","TWN":"(TWN)하지만 합법적인 수단으로 둘 사이에 어떤 얘기가 오갔을지 파악하기는 어려워 보입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_30","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래. 합법적이지 않은 수단이어야 가능하겠지.","JPN":"そう。合法的ではない手段ではなければ可能なの。","ENG":"Indeed. It would only be possible through illegitimate means.","TWN":"(TWN)그래. 합법적이지 않은 수단이어야 가능하겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_31","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하급자에게 불법적이고 비윤리적인 행위를 강요하는 건 범죄라고 생각합니다.","JPN":"下級者に違法で非倫理的な行為を強要するのは犯罪と思います。","ENG":"I believe coercing a subordinate into illegal and unethical conduct constitutes a crime.","TWN":"(TWN)하급자에게 불법적이고 비윤리적인 행위를 강요하는 건 범죄라고 생각합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_32","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"...가끔 잊는군. 자네가 언제나 내 등에 칼침 놓을 순간만 노린다는 걸.","JPN":"...たまに忘れるね。君がいつも私のなどにカルチム置く瞬間だけ狙うというガール。","ENG":"...I forget sometimes. That you're always ready to put a knife in my back at any moment.","TWN":"(TWN)...가끔 잊는군. 자네가 언제나 내 등에 칼침 놓을 순간만 노린다는 걸."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_33","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"혹시 모르니, 그 전사한 요원에 대해서도 조사해 보게.","JPN":"もしかして知らないから、その戦死した要員に対しても調査してみなさい。","ENG":"Just in case, look into that fallen operative as well.","TWN":"(TWN)혹시 모르니, 그 전사한 요원에 대해서도 조사해 보게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_34","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"현지 요원들은 동향 관찰만 지속하게 하고.","JPN":"現地要員は動向観察だけ持続させて。","ENG":"Local operatives should continue directional surveillance only.","TWN":"(TWN)현지 요원들은 동향 관찰만 지속하게 하고."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_35","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네.\xA03차 조사 자료가 갱신되는 대로\xA0연락드리겠습니다.","JPN":"はい。３次調査資料が更新され次第ご連絡致します。","ENG":"Yes. I will contact you as soon as the third investigation materials are updated.","TWN":"(TWN)네.\xA03차 조사 자료가 갱신되는 대로\xA0연락드리겠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};